"""TraceHook — 매 노드 실행 기록."""

from __future__ import annotations

import time
from typing import Any


class TraceHook:
    def __init__(self):
        self.traces: list[dict] = []
        self._start: float = 0

    async def before_node(self, node: Any, inputs: dict[str, Any]) -> dict[str, Any]:
        self._start = time.time()
        return inputs

    async def after_node(self, node: Any, result: dict[str, Any]) -> None:
        self.traces.append({
            "node_id": node.id,
            "node_name": node.name,
            "duration_ms": round((time.time() - self._start) * 1000, 2),
            "result_keys": list(result.keys()) if isinstance(result, dict) else [],
        })

    async def on_complete(self, results: dict[str, Any]) -> None:
        pass
